#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

int main()
{
	int c;
	string a;
	char b;
	cin>>c;
	cin>>a;
	for(int i=0;i<a.length();i++){
		b=a[i];
		if(a[i]>='a'&&a[i]<='z') b=(a[i]+c-'a')%26+'a';
		if(a[i]>='A'&&a[i]<='Z') b=(a[i]+c-'A')%26+'A';
		cout<<b;
	}	
	return 0;
}
